function solve(s: string): string {
    let result: string = "";

    for (let i = 0; i < s.length; i++) {
        const char = s[i];

        if (char === '*') {
            // Delete the last character if it exists
            if (result.length > 0) {
                result = result.slice(0, -1);
            }
        } else if (char === '#') {
            // Copy current result and append to itself
            result += result;
        } else if (char === '%') {
            // Reverse the current result
            result = result.split('').reverse().join('');
        } else {
            // It's a lowercase letter, add to result
            result += char;
        }
    }

    return result;
}

