fn solve(s: String) -> String {
    let mut result: String = String::new();

    for c in s.chars() {
        if c == '*' {
            if !result.is_empty() {
                result.pop();
            }
        } else if c == '#' {
            result += &result;
        } else if c == '%' {
            result = result.chars().rev().collect();
        } else {
            result.push(c);
